tiles.css:
* { box-sizing: border-box; }
html, body { margin: 0px; padding: 0px; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; color: rgb(17, 17, 17); background: rgb(255, 255, 255); }
.nav { display: flex; gap: 20px; align-items: center; padding: 16px 32px; background: rgb(17, 17, 17); color: white; }
.nav a { color: rgb(204, 204, 204); text-decoration: none; font-size: 14px; }
.nav a:hover { color: white; }
.nav .brand { font-weight: 700; font-size: 18px; color: white; margin-right: auto; letter-spacing: 1px; }
.main { padding: 48px 32px; max-width: 960px; width: 100%; margin: 0px auto; min-height: calc(-110px + 800px); }
.main h1 { font-size: 40px; margin: 0px 0px 16px; }
.main h2 { font-size: 22px; margin: 24px 0px 12px; }
.main p { font-size: 16px; line-height: 1.6; color: rgb(51, 51, 51); }
.hero { background: linear-gradient(135deg, rgb(13, 31, 60), rgb(26, 58, 106)); color: white; border-radius: 12px; padding: 48px; }
.hero h1 { color: white; }
.hero p { color: rgb(196, 209, 232); font-size: 18px; }
.hero .cta { display: inline-block; margin-top: 16px; padding: 10px 18px; background: white; color: rgb(13, 31, 60); border-radius: 6px; font-weight: 600; }
.posts { display: grid; gap: 12px; margin-top: 24px; }
.post-link { display: block; padding: 16px 20px; background: rgb(244, 246, 250); border-radius: 8px; border: 1px solid rgb(230, 233, 239); text-decoration: none; color: rgb(17, 17, 17); }
.post-link h3 { margin: 0px 0px 4px; font-size: 16px; }
.post-link p { margin: 0px; color: rgb(102, 102, 102); font-size: 13px; }
.stat-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-top: 16px; }
.stat { background: white; border: 1px solid rgb(230, 233, 239); border-radius: 8px; padding: 18px; }
.stat .num { font-size: 28px; font-weight: 700; }
.stat .label { font-size: 12px; color: rgb(136, 136, 136); text-transform: uppercase; letter-spacing: 0.5px; }
.footer { padding: 16px 32px; color: rgb(136, 136, 136); font-size: 12px; border-top: 1px solid rgb(234, 234, 234); }
.longread { max-width: 720px; margin: 0px auto; font-family: Georgia, "Times New Roman", serif; color: rgb(26, 26, 26); }
.longread h1, .longread h2, .longread h3, .longread h4 { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; letter-spacing: -0.01em; }
.lr-eyebrow { text-transform: uppercase; letter-spacing: 0.12em; font-size: 12px; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; color: rgb(107, 107, 107); margin: 0px 0px 14px; }
.longread h1 { font-size: 44px; line-height: 1.15; margin: 0px 0px 18px; }
.longread h2 { font-size: 26px; line-height: 1.3; margin: 56px 0px 14px; }
.longread h3 { font-size: 19px; line-height: 1.4; margin: 36px 0px 10px; }
.longread h4 { font-size: 15px; margin: 0px 0px 8px; }
.lr-lede { font-size: 22px; line-height: 1.55; color: rgb(42, 42, 42); font-style: italic; margin: 0px 0px 24px; }
.longread p { font-size: 18px; line-height: 1.75; color: rgb(42, 42, 42); margin: 0px 0px 20px; }
.lr-byline { display: flex; justify-content: space-between; align-items: center; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; font-size: 13px; color: rgb(107, 107, 107); border-top: 1px solid rgb(238, 238, 238); border-bottom: 1px solid rgb(238, 238, 238); padding: 14px 0px; margin: 0px 0px 36px; }
.lr-figure { margin: 36px 0px; }
.lr-figure-img { background: linear-gradient(135deg, rgb(42, 63, 106), rgb(91, 140, 255) 60%, rgb(201, 163, 255)); border-radius: 6px; height: 320px; display: grid; place-items: center; color: rgba(255, 255, 255, 0.5); font-family: monospace; font-size: 11px; text-transform: uppercase; letter-spacing: 0.2em; }
.lr-figure figcaption { margin-top: 10px; font-size: 13px; color: rgb(107, 107, 107); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; }
.longread ul, .longread ol { padding-left: 1.4em; margin: 0px 0px 24px; }
.longread li { font-size: 17px; line-height: 1.7; color: rgb(42, 42, 42); margin-bottom: 10px; }
.longread blockquote { margin: 32px 0px; padding: 0px 0px 0px 22px; border-left: 3px solid rgb(91, 140, 255); }
.longread blockquote p { font-size: 22px; font-style: italic; line-height: 1.55; color: rgb(26, 26, 26); }
.longread blockquote cite { display: block; font-size: 13px; color: rgb(107, 107, 107); font-style: normal; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; margin-top: 6px; }
.longread pre { background: rgb(14, 17, 23); color: rgb(226, 232, 240); padding: 18px 20px; border-radius: 6px; font-size: 13px; line-height: 1.6; overflow-x: auto; margin: 0px 0px 28px; }
.longread code { font-family: ui-monospace, SFMono-Regular, Menlo, monospace; }
.lr-callout { background: rgb(240, 244, 255); border: 1px solid rgb(214, 224, 255); border-radius: 8px; padding: 18px 22px; margin: 32px 0px; }
.lr-callout h4 { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; font-size: 13px; text-transform: uppercase; letter-spacing: 0.1em; color: rgb(91, 140, 255); margin: 0px 0px 8px; }
.lr-callout p { font-size: 16px; margin: 0px; }
.lr-table { width: 100%; border-collapse: collapse; margin: 0px 0px 28px; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; }
.lr-table th, .lr-table td { padding: 10px 12px; text-align: left; border-bottom: 1px solid rgb(238, 238, 238); font-size: 14px; }
.lr-table th { color: rgb(107, 107, 107); font-weight: 600; font-size: 12px; text-transform: uppercase; letter-spacing: 0.06em; }
.lr-link { color: rgb(91, 140, 255); text-decoration: underline; text-underline-offset: 2px; }
.lr-divider { border-width: 1px 0px 0px; border-style: solid none none; border-color: rgb(238, 238, 238) currentcolor currentcolor; border-image: initial; margin: 48px 0px; }
.lr-footer { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; }
.lr-tags { display: flex; gap: 8px; margin: 0px 0px 16px; }
.lr-tag { background: rgb(244, 246, 250); border: 1px solid rgb(230, 233, 239); border-radius: 999px; padding: 4px 12px; font-size: 12px; color: rgb(68, 68, 68); }
.lr-also { font-size: 14px; color: rgb(107, 107, 107); }

